SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM TC_DEPT
WHERE DEPT_TYPE_CD = #{deptTypeCd}

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM TC_DEPT
WHERE COMP_TYPE_CD = #{companyTypeCd}

SELECT *
FROM TC_DEPT
WHERE DEPT_CD = #{deptCd}

SELECT A.dept_cd AS deptCd, A.dept_nm AS deptNm, A.prnt_dept_cd AS prntDeptCd, B.dept_nm AS prntDeptNm, A.dept_type_cd AS deptTypeCd, A.comp_type_cd AS companyTypeCd, A.comp_class_cd AS compClassCd, A.dept_desc AS deptDesc, A.use_yn AS useYn, 0 AS level FROM TC_DEPT A LEFT OUTER JOIN TC_DEPT B ON A.PRNT_DEPT_CD = B.DEPT_CD WHERE A.dept_cd IN
#{item}
ORDER BY A.dept_cd

SELECT *
FROM v_dept_level
WHERE COMP_TYPE_CD = #{companyTypeCd}

SELECT *
FROM TC_DEPT
WHERE DEPT_CD = #{deptCd} OR PRNT_DEPT_CD = #{deptCd}

SELECT *
FROM v_organization_structure
WHERE DEPT_TYPE_CD = #{deptTypeCd}

SELECT COMPANY_CD
FROM v_organization_structure
WHERE ORIGIN_CD = #{deptCd}

